"use client";

import type { Blackboard01Props } from "./types";
import { BlackboardRoot } from "./parts/blackboard-root";
import { BlackboardSurface } from "./parts/blackboard-surface";
import { BlackboardNotificationBadge } from "./parts/blackboard-notification-badge";
import { BlackboardBackgroundEditor } from "./parts/blackboard-background-editor";
import { BlackboardPinnedRow } from "./parts/blackboard-pinned-row";
import { BlackboardNoteStream } from "./parts/blackboard-note-stream";
import { BlackboardComposer } from "./parts/blackboard-composer";

/**
 * Batteries-included blackboard. Pure composition over `BlackboardRoot` + the flat
 * parts, gated by `show*` toggles — contains no logic the parts don't, so any
 * hand-assembled subset behaves identically. For a lighter build, compose the
 * parts directly and drop what you don't need (e.g. omit `BlackboardComposer`).
 */
export function Blackboard01(props: Blackboard01Props) {
  const {
    showComposer,
    showNotificationBadge = true,
    showBackgroundEditor,
    showPinnedRow = true,
    ...rootProps
  } = props;

  const composerVisible = showComposer ?? !!rootProps.onPostNote;
  const bgEditorVisible = showBackgroundEditor ?? !!rootProps.editableBackground;

  return (
    <BlackboardRoot {...rootProps}>
      <BlackboardSurface>
        {showNotificationBadge ? <BlackboardNotificationBadge /> : null}
        {bgEditorVisible ? <BlackboardBackgroundEditor /> : null}
        {showPinnedRow ? <BlackboardPinnedRow /> : null}
        <BlackboardNoteStream />
        {composerVisible ? <BlackboardComposer /> : null}
      </BlackboardSurface>
    </BlackboardRoot>
  );
}

// Self-hosted handwriting fonts (hybrid delivery — bundled defaults, overridable
// via the `fonts` prop). Side-effect imports register the @font-face rules; the
// families are referenced through `--bb-font-*` CSS vars injected by BlackboardRoot.
//
// These are the only design-mandate font exception in the library, scoped to note
// text + the unread number. A consumer who fully replaces the set via `fonts` can
// fork this module to a no-op to drop the bundled weight.
//
// The type import sits ABOVE the side-effect imports deliberately: the
// `validate:meta-deps` import regex would otherwise span from the first `import`
// down to this `from`, swallowing the @fontsource side-effect imports (phantom-npm).
import type { HandwritingFont } from "./types";

import "@fontsource/kalam/300.css";
import "@fontsource/kalam/400.css";
import "@fontsource/kalam/700.css";
import "@fontsource-variable/caveat";
import "@fontsource/patrick-hand";
import "@fontsource/shadows-into-light";

/** CSS-var declarations BlackboardRoot injects on its wrapper (with cursive fallbacks). */
export const FONT_VAR_DECLARATIONS: Record<string, string> = {
  "--bb-font-kalam": '"Kalam", cursive',
  "--bb-font-caveat": '"Caveat Variable", "Caveat", cursive',
  "--bb-font-patrick": '"Patrick Hand", cursive',
  "--bb-font-shadows": '"Shadows Into Light", cursive',
};

export const DEFAULT_FONTS: HandwritingFont[] = [
  { key: "kalam", label: "Kalam", cssVar: "--bb-font-kalam", hasWeights: true },
  { key: "caveat", label: "Caveat", cssVar: "--bb-font-caveat", hasWeights: false },
  { key: "patrick", label: "Patrick Hand", cssVar: "--bb-font-patrick", hasWeights: false },
  { key: "shadows", label: "Shadows Into Light", cssVar: "--bb-font-shadows", hasWeights: false },
];

// Tier A — the batteries-included assembly
export { Blackboard01 } from "./blackboard-01";

// Tier B — headless provider + context-connected parts (flat exports)
export { BlackboardRoot } from "./parts/blackboard-root";
export { BlackboardSurface } from "./parts/blackboard-surface";
export { BlackboardPinnedRow } from "./parts/blackboard-pinned-row";
export { BlackboardNoteStream } from "./parts/blackboard-note-stream";
export { BlackboardNoteItem } from "./parts/blackboard-note-item";
export { BlackboardComposer } from "./parts/blackboard-composer";
export { BlackboardNotificationBadge } from "./parts/blackboard-notification-badge";
export { BlackboardBackgroundEditor } from "./parts/blackboard-background-editor";

// Tier C — standalone, context-free primitives
export { HandwrittenNote } from "./parts/handwritten-note";
export { NoteComposer } from "./parts/note-composer";
export { InkColorPicker } from "./parts/ink-color-picker";
export { ChalkWidthPicker } from "./parts/chalk-width-picker";
export { HandwritingFontPicker } from "./parts/handwriting-font-picker";
export { MentionPicker } from "./parts/mention-picker";
export { MentionText } from "./parts/mention-text";
export { UnreadCount } from "./parts/unread-count";
export { BoardBackground } from "./parts/board-background";

// context hook
export { useBlackboard } from "./hooks/use-blackboard";

// constants
export { DEFAULT_PALETTE, DEFAULT_WIDTHS } from "./lib/palette";
export { DEFAULT_FONTS } from "./blackboard-fonts";

// types
export type * from "./types";

// part prop types (for à-la-carte consumers)
export type { HandwrittenNoteProps } from "./parts/handwritten-note";
export type { NoteComposerProps } from "./parts/note-composer";
export type { InkColorPickerProps } from "./parts/ink-color-picker";
export type { ChalkWidthPickerProps } from "./parts/chalk-width-picker";
export type { HandwritingFontPickerProps } from "./parts/handwriting-font-picker";
export type { MentionPickerProps } from "./parts/mention-picker";
export type { MentionTextProps } from "./parts/mention-text";
export type { UnreadCountProps } from "./parts/unread-count";
export type { BoardBackgroundProps } from "./parts/board-background";
export type { BlackboardSurfaceProps } from "./parts/blackboard-surface";

import type { CSSProperties, ReactNode, Ref } from "react";

// ── identity ───────────────────────────────────────────────

export interface BlackboardAuthor {
  id: string;
  name: string;
  avatarUrl?: string;
  /** Optional per-author default ink (palette key or raw CSS color). */
  inkColor?: string;
}

/** Mention-able team roster (a superset of authors). Drives the @-picker. */
export interface BlackboardMember {
  id: string;
  name: string;
  avatarUrl?: string;
}

// ── note styling (the three writing controls) ──────────────

/** Chalk thickness. Maps to real font-weight where the font has weights, else a faux text-stroke. */
export type NoteWidth = "thin" | "regular" | "bold";

export interface NoteStyle {
  /** Palette key (e.g. "lime") or a raw CSS color when `allowFreeColor`. */
  color: string;
  width: NoteWidth;
  /** A `HandwritingFont.key`. */
  font: string;
}

export interface HandwritingFont {
  /** Stable id stored on the note ("kalam", "caveat", …). */
  key: string;
  /** Picker label ("Kalam"). */
  label: string;
  /** The CSS var the family is exposed through ("--bb-font-kalam"). */
  cssVar: string;
  /** True ⇒ real font-weight for width; false ⇒ faux text-stroke. */
  hasWeights?: boolean;
}

/** An ink swatch offered in the composer. */
export interface InkColor {
  /** Stable key stored on the note ("chalk", "lime", …). */
  key: string;
  label: string;
  /** Resolved CSS color (an oklch / hex / var()). */
  value: string;
}

// ── mentions ───────────────────────────────────────────────

export interface Mention {
  memberId: string;
  /** The "@name" exactly as written. */
  display: string;
  /** Char offset into `note.text`. */
  start: number;
  /** Length of the `display` substring. */
  length: number;
}

// ── the note ───────────────────────────────────────────────

export interface BlackboardNote {
  id: string;
  text: string;
  author: BlackboardAuthor;
  /** ISO 8601. */
  createdAt: string;
  updatedAt?: string;
  style: NoteStyle;
  /**
   * Uncontrolled pin flag. Ignored when the `pinnedNoteIds` prop is supplied
   * (that prop is the controlled source of truth).
   */
  pinned?: boolean;
  mentions?: Mention[];
  meta?: Record<string, unknown>;
  /** @internal Set on optimistic notes awaiting a server id; cleared on reconcile. */
  pending?: boolean;
  /** @internal Set when an optimistic post failed; surfaces a retry affordance. */
  failed?: boolean;
}

// ── board background ───────────────────────────────────────

export type BoardBackground =
  | { kind: "color"; value: string }
  | { kind: "image"; url: string; overlay?: number };

// ── note draft (composer ↔ callbacks) ──────────────────────

export interface NoteDraft {
  text: string;
  style: NoteStyle;
  mentions: Mention[];
}

// ── labels (i18n surface) ──────────────────────────────────

export interface Blackboard01Labels {
  composerPlaceholder: string;
  post: string;
  loadOlder: string;
  loadingOlder: string;
  pinnedHeading: string;
  empty: string;
  unreadAria: (n: number) => string;
  mentionYou: string;
  colorLabel: string;
  widthLabel: string;
  fontLabel: string;
  pin: string;
  unpin: string;
  delete: string;
  retry: string;
  doubleClickHint: string;
  closeComposer: string;
  authoredBy: (name: string) => string;
  backgroundLabel: string;
  backgroundColor: string;
  backgroundImage: string;
  backgroundImageUrl: string;
}

// ── imperative handle ──────────────────────────────────────

export interface Blackboard01Handle {
  scrollToLatest(): void;
  /** Push an inbound real-time note (dedup-safe against ids + pending optimistic notes). */
  appendNote(note: BlackboardNote): void;
  focusComposer(): void;
  markAllSeen(): void;
}

// ── root / assembly props ──────────────────────────────────

/**
 * Props shared by the headless `BlackboardRoot` provider and the `Blackboard01`
 * assembly. The assembly adds the `show*` chrome toggles.
 */
export interface BlackboardRootProps {
  /** Controlled stream, oldest → newest. */
  notes: BlackboardNote[];
  currentUser: BlackboardAuthor;
  /** Mention roster; empty/undefined ⇒ no @-picker. */
  members?: BlackboardMember[];
  /** Default true. false ⇒ composer disabled (with `renderWriteDenied`). */
  canWrite?: boolean;

  // lazy load older (scroll-up)
  onLoadOlder?(beforeNoteId: string | null, limit: number): Promise<BlackboardNote[]>;
  hasMoreOlder?: boolean;
  /** Default 10. */
  loadOlderPageSize?: number;

  // write / persist (auto-save = debounced; NO network here)
  onPostNote?(draft: NoteDraft): void | Promise<BlackboardNote>;
  onUpdateNote?(id: string, patch: Partial<NoteDraft>): void;
  onDeleteNote?(id: string): void;
  onDraftChange?(draft: NoteDraft): void;
  /** Debounce for `onDraftChange`. Default 600. */
  autoSaveDelayMs?: number;

  // pin — `pinnedNoteIds` (controlled) wins; else `note.pinned` (uncontrolled).
  pinnedNoteIds?: string[];
  onPinNote?(id: string): void;
  onUnpinNote?(id: string): void;

  // mentions — fires AFTER onPostNote resolves, with the reconciled note id.
  onMention?(noteId: string, memberIds: string[]): void;

  // unread marker
  unreadCount?: number;
  lastSeenNoteId?: string | null;
  onSeen?(latestNoteId: string): void;

  // board theming
  background?: BoardBackground;
  defaultBackground?: BoardBackground;
  onBackgroundChange?(bg: BoardBackground): void;
  editableBackground?: boolean;

  // writing palette constraints
  palette?: InkColor[];
  fonts?: HandwritingFont[];
  widths?: NoteWidth[];
  allowFreeColor?: boolean;
  defaultStyle?: Partial<NoteStyle>;

  // behaviour
  /** Default false (newest at bottom). */
  newestFirst?: boolean;
  /** Default true. */
  showAuthorOnHover?: boolean;
  /**
   * How the composer is revealed. `"double-click"` (default) keeps the board clean
   * and opens the composer when the user double-clicks the surface; `"always"` keeps
   * it docked at the bottom. Ignored when there's no composer (no `onPostNote`).
   */
  composerMode?: "always" | "double-click";

  // escape hatches
  renderWriteDenied?(): ReactNode;
  renderEmpty?(): ReactNode;
  labels?: Partial<Blackboard01Labels>;

  children?: ReactNode;
  className?: string;
  style?: CSSProperties;
  ref?: Ref<Blackboard01Handle>;
}

export interface Blackboard01Props extends Omit<BlackboardRootProps, "children"> {
  // chrome toggles (compound assembly)
  /** Default = `!!onPostNote`. */
  showComposer?: boolean;
  /** Default true. */
  showNotificationBadge?: boolean;
  /** Default = `editableBackground`. */
  showBackgroundEditor?: boolean;
  /** Default true. */
  showPinnedRow?: boolean;
}

import { useEffect, useRef } from "react";
import type { NoteDraft } from "../types";

/**
 * Debounced draft autosave. Fires `onDraftChange` `delayMs` after the draft stops
 * changing — "auto-save" = no data loss + no mandatory Save click, NOT a per-keystroke
 * post. Skips the very first run (mount) so an empty initial draft doesn't fire.
 */
export function useAutosave(
  draft: NoteDraft,
  onDraftChange: ((draft: NoteDraft) => void) | undefined,
  delayMs: number,
): void {
  const cbRef = useRef(onDraftChange);
  useEffect(() => {
    cbRef.current = onDraftChange;
  });

  const mountedRef = useRef(false);
  useEffect(() => {
    if (!mountedRef.current) {
      mountedRef.current = true;
      return;
    }
    if (!cbRef.current) return;
    const id = setTimeout(() => cbRef.current?.(draft), delayMs);
    return () => clearTimeout(id);
  }, [draft, delayMs]);
}

"use client";

import { createContext, useContext } from "react";
import type { RefObject, ReactNode } from "react";
import type {
  Blackboard01Labels,
  BlackboardAuthor,
  BlackboardMember,
  BlackboardNote,
  BoardBackground,
  HandwritingFont,
  InkColor,
  NoteDraft,
  NoteStyle,
  NoteWidth,
} from "../types";

/** The value shared by every context-connected part. Built by `useBlackboardController`. */
export interface BlackboardContextValue {
  labels: Required<Blackboard01Labels>;
  currentUser: BlackboardAuthor;
  members: BlackboardMember[];
  canWrite: boolean;

  // display
  streamNotes: BlackboardNote[]; // chronological (oldest→newest); pinned lifted out
  pinnedNotes: BlackboardNote[];
  newestFirst: boolean;
  isPinned: (id: string) => boolean;
  showAuthorOnHover: boolean;
  mentionsCurrentUser: (note: BlackboardNote) => boolean;

  // palette / fonts
  palette: InkColor[];
  fonts: HandwritingFont[];
  widths: NoteWidth[];
  allowFreeColor: boolean;

  // composer / draft
  composerRef: RefObject<HTMLTextAreaElement | null>;
  draft: NoteDraft;
  setDraftText: (text: string) => void;
  setDraftStyle: (patch: Partial<NoteStyle>) => void;
  post: () => void;
  posting: boolean;
  composerMode: "always" | "double-click";
  composerOpen: boolean;
  openComposer: () => void;
  closeComposer: () => void;

  // lazy load
  scrollRef: RefObject<HTMLDivElement | null>;
  sentinelRef: RefObject<HTMLDivElement | null>;
  hasMoreOlder: boolean;
  loadingOlder: boolean;
  loadOlderEnabled: boolean;
  loadOlder: () => Promise<void>;
  onReachedBottom: () => void;
  scrollToLatest: () => void;

  // unread
  unreadCount: number;
  markAllSeen: () => void;

  // pin / delete / retry
  canPin: boolean;
  togglePin: (note: BlackboardNote) => void;
  canDelete: boolean;
  deleteNote: (note: BlackboardNote) => void;
  retryPost: (id: string) => void;

  // background
  background: BoardBackground;
  setBackground: (bg: BoardBackground) => void;
  editableBackground: boolean;

  renderWriteDenied?: () => ReactNode;
  renderEmpty?: () => ReactNode;
}

const BlackboardContext = createContext<BlackboardContextValue | null>(null);

export { BlackboardContext };

/** Read the blackboard context. Throws if used outside `<BlackboardRoot>`. */
export function useBlackboard(): BlackboardContextValue {
  const ctx = useContext(BlackboardContext);
  if (ctx === null) {
    throw new Error("useBlackboard must be used within <BlackboardRoot> (or <Blackboard01>).");
  }
  return ctx;
}

export const DEFAULT_BLACKBOARD_LABELS: Required<Blackboard01Labels> = {
  composerPlaceholder: "Write a note…",
  post: "Post",
  loadOlder: "Load older notes",
  loadingOlder: "Loading…",
  pinnedHeading: "Pinned",
  empty: "Nothing on the board yet",
  unreadAria: (n) => `${n} unread ${n === 1 ? "note" : "notes"}`,
  mentionYou: "@you",
  colorLabel: "Ink color",
  widthLabel: "Chalk width",
  fontLabel: "Handwriting",
  pin: "Pin",
  unpin: "Unpin",
  delete: "Delete",
  retry: "Retry",
  doubleClickHint: "Double-click to write a note",
  closeComposer: "Close composer",
  authoredBy: (name) => name,
  backgroundLabel: "Board background",
  backgroundColor: "Color",
  backgroundImage: "Image",
  backgroundImageUrl: "Image URL",
};

export const DEFAULT_BACKGROUND: BoardBackground = {
  kind: "color",
  value: "oklch(0.18 0.04 250)",
};

"use client";

import { useCallback, useImperativeHandle, useMemo, useRef, useState } from "react";
import type {
  Blackboard01Handle,
  BlackboardNote,
  BlackboardRootProps,
  BoardBackground,
  NoteDraft,
  NoteStyle,
} from "../types";
import {
  DEFAULT_NOTE_STYLE,
  DEFAULT_PALETTE,
  DEFAULT_WIDTHS,
} from "../lib/palette";
import { DEFAULT_FONTS } from "../blackboard-fonts";
import { dedupeMemberIds, extractMentions } from "../lib/mentions";
import { deriveUnread, latestNoteId } from "../lib/unread";
import { useControllableState } from "./use-controllable-state";
import { useAutosave } from "./use-autosave";
import { useLazyOlder } from "./use-lazy-older";
import {
  BlackboardContext,
  DEFAULT_BACKGROUND,
  DEFAULT_BLACKBOARD_LABELS,
  type BlackboardContextValue,
} from "./use-blackboard";

function genTempId(): string {
  // Event-handler-only (post/retry) — never called during SSR render.
  const rnd =
    typeof crypto !== "undefined" && "randomUUID" in crypto
      ? crypto.randomUUID()
      : `${performance.now()}`;
  return `bb-temp-${rnd}`;
}

function nowIso(): string {
  return new Date().toISOString();
}

/**
 * The headless controller — builds the full `BlackboardContextValue` from
 * `BlackboardRootProps`. Owns optimistic posting + reconcile, lazy-load cursor,
 * draft + autosave, pin (controlled or uncontrolled), unread derivation, board
 * theming, and the imperative handle.
 */
export function useBlackboardController(props: BlackboardRootProps): BlackboardContextValue {
  const {
    notes,
    currentUser,
    members = [],
    canWrite = true,
    onLoadOlder,
    hasMoreOlder = false,
    loadOlderPageSize = 10,
    onPostNote,
    onDeleteNote,
    onDraftChange,
    autoSaveDelayMs = 600,
    pinnedNoteIds,
    onPinNote,
    onUnpinNote,
    onMention,
    unreadCount,
    lastSeenNoteId,
    onSeen,
    background,
    defaultBackground,
    onBackgroundChange,
    editableBackground = false,
    palette = DEFAULT_PALETTE,
    fonts = DEFAULT_FONTS,
    widths = DEFAULT_WIDTHS,
    allowFreeColor = false,
    defaultStyle,
    newestFirst = false,
    showAuthorOnHover = true,
    composerMode = "double-click",
    renderWriteDenied,
    renderEmpty,
    labels: labelOverrides,
    ref,
  } = props;

  const labels = useMemo(
    () => ({ ...DEFAULT_BLACKBOARD_LABELS, ...labelOverrides }),
    [labelOverrides],
  );

  // refs
  const composerRef = useRef<HTMLTextAreaElement | null>(null);
  const scrollRef = useRef<HTMLDivElement | null>(null);
  const sentinelRef = useRef<HTMLDivElement | null>(null);

  // ── optimistic / appended notes (local) ──────────────────
  const [extras, setExtras] = useState<BlackboardNote[]>([]);
  const [posting, setPosting] = useState(false);

  // ── composer reveal ──────────────────────────────────────
  const [composerOpenState, setComposerOpenState] = useState(false);
  const composerOpen = composerMode === "always" ? true : composerOpenState;
  const openComposer = useCallback(() => {
    setComposerOpenState(true);
    requestAnimationFrame(() => composerRef.current?.focus());
  }, []);
  const closeComposer = useCallback(() => setComposerOpenState(false), []);

  // Display = controlled `notes` ∪ local extras (optimistic posts, real-time
  // appends, loaded-older pages), deduped by id with `notes` winning. Extras whose
  // id is now in `notes` are filtered out here (no prune effect needed — that would
  // be a set-state-in-effect cascade). Reconciled extras linger harmlessly; growth
  // is bounded in `setExtras` callers. (v0.1.1: opportunistic prune of absorbed extras.)
  const merged = useMemo(() => {
    const propIds = new Set(notes.map((n) => n.id));
    const extraOnly = extras.filter((e) => !propIds.has(e.id));
    const all = [...notes, ...extraOnly];
    all.sort((a, b) => (a.createdAt < b.createdAt ? -1 : a.createdAt > b.createdAt ? 1 : 0));
    return all;
  }, [notes, extras]);

  // ── pin (controlled `pinnedNoteIds` XOR uncontrolled `note.pinned`) ──
  const pinControlled = pinnedNoteIds !== undefined;
  const [localPinned, setLocalPinned] = useState<Set<string>>(
    () => new Set(notes.filter((n) => n.pinned).map((n) => n.id)),
  );
  const pinnedSet = useMemo(
    () => (pinControlled ? new Set(pinnedNoteIds) : localPinned),
    [pinControlled, pinnedNoteIds, localPinned],
  );
  const isPinned = useCallback((id: string) => pinnedSet.has(id), [pinnedSet]);

  const streamNotes = useMemo(() => merged.filter((n) => !pinnedSet.has(n.id)), [merged, pinnedSet]);
  const pinnedNotes = useMemo(() => merged.filter((n) => pinnedSet.has(n.id)), [merged, pinnedSet]);

  const canPin = !!onPinNote;
  const togglePin = useCallback(
    (note: BlackboardNote) => {
      const willPin = !pinnedSet.has(note.id);
      if (willPin) onPinNote?.(note.id);
      else onUnpinNote?.(note.id);
      if (!pinControlled) {
        setLocalPinned((prev) => {
          const next = new Set(prev);
          if (willPin) next.add(note.id);
          else next.delete(note.id);
          return next;
        });
      }
    },
    [pinnedSet, onPinNote, onUnpinNote, pinControlled],
  );

  // ── background (controlled / uncontrolled) ───────────────
  const [bg, setBg] = useControllableState<BoardBackground>({
    value: background,
    defaultValue: defaultBackground ?? DEFAULT_BACKGROUND,
    onChange: onBackgroundChange,
    componentName: "Blackboard01",
    valuePropName: "background",
  });

  // ── draft + autosave ─────────────────────────────────────
  const [draft, setDraft] = useState<NoteDraft>(() => ({
    text: "",
    style: { ...DEFAULT_NOTE_STYLE, ...defaultStyle },
    mentions: [],
  }));
  const setDraftText = useCallback(
    (text: string) => setDraft((d) => ({ ...d, text })),
    [],
  );
  const setDraftStyle = useCallback(
    (patch: Partial<NoteStyle>) => setDraft((d) => ({ ...d, style: { ...d.style, ...patch } })),
    [],
  );
  useAutosave(draft, onDraftChange, autoSaveDelayMs);

  // ── scroll helpers ───────────────────────────────────────
  const scrollToLatest = useCallback(() => {
    requestAnimationFrame(() => {
      const el = scrollRef.current;
      if (!el) return;
      el.scrollTop = newestFirst ? 0 : el.scrollHeight;
    });
  }, [newestFirst]);

  // ── unread ───────────────────────────────────────────────
  const seenControlled = lastSeenNoteId !== undefined;
  const [localSeenId, setLocalSeenId] = useState<string | null>(null);
  const effectiveSeen = seenControlled ? lastSeenNoteId ?? null : localSeenId;
  const derivedUnread = deriveUnread(merged, effectiveSeen);
  const effectiveUnread = unreadCount ?? derivedUnread;

  const markAllSeen = useCallback(() => {
    const latest = latestNoteId(merged);
    if (latest) onSeen?.(latest);
    if (!seenControlled) setLocalSeenId(latest);
  }, [merged, onSeen, seenControlled]);

  const onReachedBottom = useCallback(() => {
    if (!newestFirst) markAllSeen();
  }, [newestFirst, markAllSeen]);

  // ── posting (optimistic + reconcile) ─────────────────────
  const submit = useCallback(
    (optimistic: BlackboardNote) => {
      const mentions = optimistic.mentions ?? [];
      const memberIds = dedupeMemberIds(mentions);
      const result = onPostNote?.({ text: optimistic.text, style: optimistic.style, mentions });
      if (result instanceof Promise) {
        setPosting(true);
        result
          .then((real) => {
            setExtras((prev) => prev.map((e) => (e.id === optimistic.id ? { ...real } : e)));
            if (memberIds.length) onMention?.(real.id, memberIds);
          })
          .catch(() => {
            setExtras((prev) =>
              prev.map((e) =>
                e.id === optimistic.id ? { ...e, pending: false, failed: true } : e,
              ),
            );
          })
          .finally(() => setPosting(false));
      } else {
        // sync / void: drop the pending flag; fire mention with the optimistic id
        setExtras((prev) =>
          prev.map((e) => (e.id === optimistic.id ? { ...e, pending: false } : e)),
        );
        if (memberIds.length) onMention?.(optimistic.id, memberIds);
      }
    },
    [onPostNote, onMention],
  );

  const post = useCallback(() => {
    const text = draft.text.trim();
    if (!canWrite || !onPostNote || !text) return;
    const mentions = extractMentions(text, members);
    const optimistic: BlackboardNote = {
      id: genTempId(),
      text,
      author: currentUser,
      createdAt: nowIso(),
      style: draft.style,
      mentions,
      pending: true,
    };
    setExtras((prev) => [...prev, optimistic]);
    setDraft((d) => ({ ...d, text: "", mentions: [] }));
    submit(optimistic);
    scrollToLatest();
  }, [draft.text, draft.style, canWrite, onPostNote, members, currentUser, submit, scrollToLatest]);

  const retryPost = useCallback(
    (id: string) => {
      setExtras((prev) => {
        const note = prev.find((e) => e.id === id);
        if (note) submit({ ...note, pending: true, failed: false });
        return prev.map((e) => (e.id === id ? { ...e, pending: true, failed: false } : e));
      });
    },
    [submit],
  );

  // ── delete ───────────────────────────────────────────────
  const canDelete = !!onDeleteNote;
  const deleteNote = useCallback(
    (note: BlackboardNote) => {
      if (note.failed) {
        // dismiss a failed optimistic note locally
        setExtras((prev) => prev.filter((e) => e.id !== note.id));
        return;
      }
      onDeleteNote?.(note.id);
      setExtras((prev) => prev.filter((e) => e.id !== note.id));
    },
    [onDeleteNote],
  );

  // ── lazy load older ──────────────────────────────────────
  const loadOlder = useCallback(async () => {
    if (!onLoadOlder) return;
    const oldest = merged.find((n) => !n.pending && !n.failed);
    const older = await onLoadOlder(oldest ? oldest.id : null, loadOlderPageSize);
    if (older.length === 0) return;
    // Prepend any that aren't already present (consumer owns `notes`, but we
    // surface them immediately via extras; the prune effect reconciles).
    setExtras((prev) => {
      const known = new Set([...notes.map((n) => n.id), ...prev.map((e) => e.id)]);
      const fresh = older.filter((o) => !known.has(o.id));
      return fresh.length ? [...fresh, ...prev] : prev;
    });
  }, [onLoadOlder, merged, loadOlderPageSize, notes]);

  const { loadingOlder } = useLazyOlder({
    scrollRef,
    sentinelRef,
    load: loadOlder,
    hasMore: hasMoreOlder,
    enabled: !!onLoadOlder,
    topId: streamNotes.length > 0 ? streamNotes[0].id : null,
    anchor: !newestFirst,
  });

  // ── mention emphasis ─────────────────────────────────────
  const mentionsCurrentUser = useCallback(
    (note: BlackboardNote) => !!note.mentions?.some((m) => m.memberId === currentUser.id),
    [currentUser.id],
  );

  // ── imperative handle ────────────────────────────────────
  useImperativeHandle(
    ref,
    (): Blackboard01Handle => ({
      scrollToLatest,
      appendNote: (note) => {
        setExtras((prev) => {
          if (prev.some((e) => e.id === note.id)) return prev;
          // Cap the local buffer so a long-lived real-time stream can't grow unbounded.
          const next = [...prev, note];
          return next.length > 300 ? next.slice(next.length - 300) : next;
        });
        scrollToLatest();
      },
      focusComposer: () => composerRef.current?.focus(),
      markAllSeen,
    }),
    [scrollToLatest, markAllSeen],
  );

  return {
    labels,
    currentUser,
    members,
    canWrite,
    streamNotes,
    pinnedNotes,
    newestFirst,
    isPinned,
    showAuthorOnHover,
    mentionsCurrentUser,
    palette,
    fonts,
    widths,
    allowFreeColor,
    composerRef,
    draft,
    setDraftText,
    setDraftStyle,
    post,
    posting,
    composerMode,
    composerOpen,
    openComposer,
    closeComposer,
    scrollRef,
    sentinelRef,
    hasMoreOlder,
    loadingOlder,
    loadOlderEnabled: !!onLoadOlder,
    loadOlder,
    onReachedBottom,
    scrollToLatest,
    unreadCount: effectiveUnread,
    markAllSeen,
    canPin,
    togglePin,
    canDelete,
    deleteNote,
    retryPost,
    background: bg,
    setBackground: setBg,
    editableBackground,
    renderWriteDenied,
    renderEmpty,
  } satisfies BlackboardContextValue;
}

export { BlackboardContext };

import { useCallback, useEffect, useRef, useState } from "react";

interface UseControllableStateOpts<T> {
  /** Controlled value. When provided, state is fully controlled by parent. */
  value?: T;
  /** Initial value for uncontrolled mode. */
  defaultValue: T;
  /** Fires on every state change (both modes). */
  onChange?: (next: T) => void;
  /** Component name used in dev warnings. */
  componentName: string;
  /** Prop name used in dev warnings (e.g., `"background"`). */
  valuePropName: string;
}

/**
 * Controlled+uncontrolled state helper. Sealed copy of the proven generic used
 * across the library (account-switcher-01, code-block, media-library-01) —
 * registry portability bans a shared cross-component module, so each procomp
 * vendors its own. Locks the mode at first render and dev-warns on mode-flip.
 */
export function useControllableState<T>({
  value,
  defaultValue,
  onChange,
  componentName,
  valuePropName,
}: UseControllableStateOpts<T>): readonly [T, (next: T) => void] {
  const [internal, setInternal] = useState<T>(defaultValue);
  const isControlled = value !== undefined;
  const onChangeRef = useRef(onChange);
  useEffect(() => {
    onChangeRef.current = onChange;
  });

  const wasControlledRef = useRef(isControlled);
  useEffect(() => {
    if (process.env.NODE_ENV === "production") return;
    if (wasControlledRef.current !== isControlled) {
      console.warn(
        `[${componentName}] \`${valuePropName}\` switched from ${
          wasControlledRef.current ? "controlled" : "uncontrolled"
        } to ${
          isControlled ? "controlled" : "uncontrolled"
        } mode. Components should not switch modes mid-life; pick one at mount.`,
      );
      wasControlledRef.current = isControlled;
    }
  }, [isControlled, componentName, valuePropName]);

  const current = isControlled ? (value as T) : internal;

  const set = useCallback(
    (next: T) => {
      if (!isControlled) setInternal(next);
      onChangeRef.current?.(next);
    },
    [isControlled],
  );

  return [current, set] as const;
}

import { useCallback, useEffect, useLayoutEffect, useRef, useState } from "react";
import type { RefObject } from "react";

interface UseLazyOlderOpts {
  scrollRef: RefObject<HTMLElement | null>;
  sentinelRef: RefObject<HTMLElement | null>;
  /** Fetch + prepend the next older page. Resolves once state has been updated. */
  load: () => Promise<void>;
  hasMore: boolean;
  enabled: boolean;
  /** The id of the current top note — changes when an older page prepends. */
  topId: string | null;
  /** When true (newest-at-bottom), preserve scroll position across a top-prepend. */
  anchor: boolean;
}

/**
 * Drives scroll-up lazy loading: an IntersectionObserver on a top sentinel triggers
 * `load()` when it scrolls into view (guarded against re-entry), and — in anchor mode —
 * preserves the viewport so prepended notes don't make the content jump.
 */
export function useLazyOlder({
  scrollRef,
  sentinelRef,
  load,
  hasMore,
  enabled,
  topId,
  anchor,
}: UseLazyOlderOpts): { loadingOlder: boolean } {
  const [loadingOlder, setLoadingOlder] = useState(false);
  const loadingRef = useRef(false);
  const prevHeightRef = useRef<number | null>(null);

  const trigger = useCallback(async () => {
    if (loadingRef.current || !hasMore || !enabled) return;
    loadingRef.current = true;
    setLoadingOlder(true);
    if (anchor && scrollRef.current) prevHeightRef.current = scrollRef.current.scrollHeight;
    try {
      await load();
    } finally {
      loadingRef.current = false;
      setLoadingOlder(false);
    }
  }, [hasMore, enabled, anchor, load, scrollRef]);

  // Restore scroll position after a top-prepend (anchor mode only).
  useLayoutEffect(() => {
    const el = scrollRef.current;
    if (!anchor || el == null || prevHeightRef.current == null) return;
    const delta = el.scrollHeight - prevHeightRef.current;
    if (delta > 0) el.scrollTop += delta;
    prevHeightRef.current = null;
    // Keyed on topId: fires exactly when the leading note changes (a prepend).
  }, [topId, anchor, scrollRef]);

  // Observe the sentinel within the scroll container.
  useEffect(() => {
    const root = scrollRef.current;
    const sentinel = sentinelRef.current;
    if (!root || !sentinel || !enabled || !hasMore) return;
    const io = new IntersectionObserver(
      (entries) => {
        if (entries.some((e) => e.isIntersecting)) void trigger();
      },
      { root, rootMargin: "120px 0px 0px 0px", threshold: 0 },
    );
    io.observe(sentinel);
    return () => io.disconnect();
  }, [scrollRef, sentinelRef, enabled, hasMore, trigger]);

  return { loadingOlder };
}

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import type { KeyboardEvent, RefObject } from "react";
import type { BlackboardMember } from "../types";
import {
  detectActiveMention,
  filterMembers,
  insertMention,
  type ActiveMention,
} from "../lib/mentions";

interface UseMentionsOpts {
  textareaRef: RefObject<HTMLTextAreaElement | null>;
  text: string;
  members: BlackboardMember[];
  setText: (text: string) => void;
}

interface UseMentionsApi {
  active: ActiveMention | null;
  candidates: BlackboardMember[];
  highlight: number;
  setHighlight: (i: number) => void;
  /** Recompute the active mention from the caret (call on input / click / keyup). */
  refresh: () => void;
  choose: (member: BlackboardMember) => void;
  close: () => void;
  /** Returns true if the keydown was consumed (open + nav keys). */
  onKeyDown: (e: KeyboardEvent<HTMLTextAreaElement>) => boolean;
}

/**
 * Wires `@`-mention detection to a controlled textarea. The picker is anchored to
 * the composer (NOT a Popover primitive / PopoverAnchor — Base UI lacks it, per
 * F-cross-13). Keyboard: ↑/↓ to move, Enter/Tab to choose, Esc to dismiss.
 */
export function useMentions({
  textareaRef,
  text,
  members,
  setText,
}: UseMentionsOpts): UseMentionsApi {
  const [active, setActive] = useState<ActiveMention | null>(null);
  const [highlight, setHighlight] = useState(0);
  const pendingCaret = useRef<number | null>(null);

  const enabled = members.length > 0;

  const candidates = useMemo(
    () => (active && enabled ? filterMembers(members, active.query) : []),
    [active, enabled, members],
  );

  const close = useCallback(() => setActive(null), []);

  const refresh = useCallback(() => {
    if (!enabled) return;
    const el = textareaRef.current;
    if (!el) return;
    const next = detectActiveMention(el.value, el.selectionStart ?? el.value.length);
    setActive(next);
    setHighlight(0);
  }, [enabled, textareaRef]);

  const choose = useCallback(
    (member: BlackboardMember) => {
      if (!active) return;
      const { text: nextText, caret } = insertMention(text, active, member);
      pendingCaret.current = caret;
      setText(nextText);
      setActive(null);
    },
    [active, text, setText],
  );

  // Restore the caret after a controlled-value insert lands in the DOM.
  useEffect(() => {
    if (pendingCaret.current == null) return;
    const el = textareaRef.current;
    if (el) {
      el.focus();
      el.setSelectionRange(pendingCaret.current, pendingCaret.current);
    }
    pendingCaret.current = null;
  }, [text, textareaRef]);

  const onKeyDown = useCallback(
    (e: KeyboardEvent<HTMLTextAreaElement>): boolean => {
      if (!active || candidates.length === 0) return false;
      if (e.key === "ArrowDown") {
        e.preventDefault();
        setHighlight((h) => (h + 1) % candidates.length);
        return true;
      }
      if (e.key === "ArrowUp") {
        e.preventDefault();
        setHighlight((h) => (h - 1 + candidates.length) % candidates.length);
        return true;
      }
      if (e.key === "Enter" || e.key === "Tab") {
        e.preventDefault();
        choose(candidates[highlight]);
        return true;
      }
      if (e.key === "Escape") {
        e.preventDefault();
        close();
        return true;
      }
      return false;
    },
    [active, candidates, highlight, choose, close],
  );

  return { active, candidates, highlight, setHighlight, refresh, choose, close, onKeyDown };
}

import type { BlackboardMember, Mention } from "../types";

/** A `@` token currently being typed: its start offset + the query after the `@`. */
export interface ActiveMention {
  /** Index of the `@`. */
  at: number;
  /** Text between `@` and the caret. */
  query: string;
}

const MENTION_BOUNDARY = /[\s.,!?;:()[\]{}"']/;

/**
 * Given the full text and the caret position, detect whether the caret sits inside
 * an in-progress `@mention` token. Returns null if not (e.g. there's whitespace
 * between the `@` and the caret, or no `@` precedes the caret on this run).
 */
export function detectActiveMention(text: string, caret: number): ActiveMention | null {
  // Walk backwards from the caret to find a preceding "@" with no boundary char in between.
  for (let i = caret - 1; i >= 0; i--) {
    const ch = text[i];
    if (ch === "@") {
      // "@" must start the string or follow a boundary char (avoid emails like a@b).
      const prev = text[i - 1];
      if (i === 0 || MENTION_BOUNDARY.test(prev)) {
        return { at: i, query: text.slice(i + 1, caret) };
      }
      return null;
    }
    if (MENTION_BOUNDARY.test(ch)) return null;
  }
  return null;
}

/** Filter members by a (case-insensitive) name query. */
export function filterMembers(members: BlackboardMember[], query: string): BlackboardMember[] {
  const q = query.trim().toLowerCase();
  if (!q) return members.slice(0, 8);
  return members.filter((m) => m.name.toLowerCase().includes(q)).slice(0, 8);
}

/**
 * Insert a chosen member as an `@name ` token, replacing the active `@query`.
 * Returns the new text + the caret position after the inserted token.
 */
export function insertMention(
  text: string,
  active: ActiveMention,
  member: BlackboardMember,
): { text: string; caret: number } {
  const token = `@${member.name}`;
  const before = text.slice(0, active.at);
  const after = text.slice(active.at + 1 + active.query.length);
  const insert = `${token} `;
  return { text: before + insert + after, caret: before.length + insert.length };
}

/**
 * Re-scan the final text against the roster and produce the canonical `mentions[]`
 * (offset-anchored). Longest names first so "@Anna Lee" wins over "@Anna".
 */
export function extractMentions(text: string, members: BlackboardMember[]): Mention[] {
  const byLongest = [...members].sort((a, b) => b.name.length - a.name.length);
  const out: Mention[] = [];
  const claimed: boolean[] = new Array(text.length).fill(false);

  for (const m of byLongest) {
    const needle = `@${m.name}`;
    let from = 0;
    for (;;) {
      const idx = text.indexOf(needle, from);
      if (idx === -1) break;
      const end = idx + needle.length;
      const prevOk = idx === 0 || MENTION_BOUNDARY.test(text[idx - 1]);
      const nextOk = end >= text.length || MENTION_BOUNDARY.test(text[end]);
      const free = !claimed.slice(idx, end).some(Boolean);
      if (prevOk && nextOk && free) {
        out.push({ memberId: m.id, display: needle, start: idx, length: needle.length });
        for (let k = idx; k < end; k++) claimed[k] = true;
      }
      from = idx + 1;
    }
  }
  return out.sort((a, b) => a.start - b.start);
}

/** Unique member ids referenced by a mention list. */
export function dedupeMemberIds(mentions: Mention[]): string[] {
  return Array.from(new Set(mentions.map((m) => m.memberId)));
}

import type { InkColor, NoteStyle, NoteWidth } from "../types";

/**
 * Curated chalk-tone ink palette. Muted (chroma ≤ 0.20), legible on the dark-navy
 * board, token-aligned. Overridable via the `palette` prop. Keeps the wall coherent
 * vs. a free color wheel (which is an opt-in via `allowFreeColor`).
 */
export const DEFAULT_PALETTE: InkColor[] = [
  { key: "chalk", label: "Chalk", value: "oklch(0.96 0.01 250)" },
  { key: "lime", label: "Lime", value: "oklch(0.86 0.18 132)" },
  { key: "sky", label: "Sky", value: "oklch(0.82 0.12 230)" },
  { key: "amber", label: "Amber", value: "oklch(0.84 0.14 80)" },
  { key: "rose", label: "Rose", value: "oklch(0.80 0.14 18)" },
];

export const DEFAULT_WIDTHS: NoteWidth[] = ["thin", "regular", "bold"];

/** The chalk-red used for the unread number (semantic, chroma-capped). */
export const UNREAD_RED = "oklch(0.66 0.19 22)";

export const DEFAULT_NOTE_STYLE: NoteStyle = {
  color: "chalk",
  width: "regular",
  font: "kalam",
};

/** Resolve a note's stored color key (or raw color) to a CSS color. */
export function resolveInk(color: string, palette: InkColor[]): string {
  const hit = palette.find((p) => p.key === color);
  return hit ? hit.value : color; // raw CSS color passthrough (free-color mode)
}

/** Map a width level to a real font-weight. */
export function weightForWidth(width: NoteWidth): number {
  return width === "thin" ? 300 : width === "bold" ? 700 : 400;
}

/** Faux chalk-stroke width (px) for single-weight fonts. */
export function strokeForWidth(width: NoteWidth): number {
  return width === "thin" ? 0 : width === "bold" ? 0.9 : 0.4;
}

import type { BlackboardNote } from "../types";

/**
 * Derive the unread count: notes strictly after `lastSeenNoteId` in the stream.
 * `notes` is oldest → newest. A null/unknown lastSeen ⇒ everything is unread.
 * Pending/failed optimistic notes never count.
 */
export function deriveUnread(
  notes: BlackboardNote[],
  lastSeenNoteId: string | null | undefined,
): number {
  const real = notes.filter((n) => !n.pending && !n.failed);
  if (!lastSeenNoteId) return real.length;
  const idx = real.findIndex((n) => n.id === lastSeenNoteId);
  if (idx === -1) return real.length; // last-seen note no longer present → treat all as unread
  return real.length - idx - 1;
}

/** The newest real note's id, or null. */
export function latestNoteId(notes: BlackboardNote[]): string | null {
  for (let i = notes.length - 1; i >= 0; i--) {
    if (!notes[i].pending && !notes[i].failed) return notes[i].id;
  }
  return null;
}

